PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?activeCycloneCount ?cyclone ?name ?maxSustainedWindSpeed
WHERE {
  {
    SELECT (COUNT(DISTINCT ?cyclone) AS ?activeCycloneCount)
    WHERE {
      ?cyclone a goo:HurricaneEventRecord  ;
               goo:basin "ATL"^^xsd:string ;
               goo:eventStartTime ?start ;
               goo:eventEndTime ?end .
      FILTER (
        ?start < "2024-10-07T00:00:00+00:00"^^xsd:dateTime &&
        ?end >= "2024-10-06T00:00:00+00:00"^^xsd:dateTime
      )
    }
  }
  ?cyclone a goo:HurricaneEventRecord ;
           schema:name ?name ;
           goo:maxSustainedWindSpeed ?maxSustainedWindSpeed ;
           goo:basin "ATL"^^xsd:string ;
           goo:eventStartTime ?start ;
           goo:eventEndTime ?end .
  FILTER (
    ?start < "2024-10-07T00:00:00+00:00"^^xsd:dateTime &&
    ?end >= "2024-10-06T00:00:00+00:00"^^xsd:dateTime
  )
}
ORDER BY ?name

