PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?state ?count2020 ?count2010 (?count2020 - ?count2010 AS ?difference)
WHERE {
  ?state a goo:State .
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?event2020) AS ?count2020Raw)
    WHERE {
      ?event2020 a goo:StormEventRecord ;
                 goo:occurredInState ?state ;
                 goo:eventStartTime ?start2020 .
      FILTER (YEAR(?start2020) = 2020)
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?event2010) AS ?count2010Raw)
    WHERE {
      ?event2010 a goo:StormEventRecord ;
                 goo:occurredInState ?state ;
                 goo:eventStartTime ?start2010 .
      FILTER (YEAR(?start2010) = 2010)
    }
    GROUP BY ?state
  }
  BIND(COALESCE(?count2020Raw, 0) AS ?count2020)
  BIND(COALESCE(?count2010Raw, 0) AS ?count2010)
  FILTER (?count2020 > 0 || ?count2010 > 0)
}
ORDER BY DESC(ABS(?difference)) ?state

PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX schema:     <http://schema.org/>
PREFIX geosparql:  <http://www.opengis.net/ont/geosparql#>
PREFIX geof:       <http://www.opengis.net/def/function/geosparql/>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?hurricaneCount ?cyclone ?name ?landfallDate
WHERE {
  {
    SELECT (COUNT(DISTINCT ?cyclone) AS ?hurricaneCount)
    WHERE {
      gokg:LouisianaState geosparql:hasGeometry ?stateGeom .
      ?stateGeom geosparql:asWKT ?stateWKT .
      ?cyclone a goo:HurricaneEventRecord ;
               goo:hasTrackRecord ?track .
      ?track a goo:HurricaneTrackRecord ;
             goo:recordDateTime ?trackDate ;
             goo:status "HU"^^xsd:string ;
             goo:lat ?trackLat ;
             goo:lon ?trackLon .
      BIND(STRDT(CONCAT("POINT(", STR(?trackLon), " ", STR(?trackLat), ")"), geosparql:wktLiteral) AS ?trackPoint)
      FILTER (MONTH(?trackDate) = 8)
      FILTER (geof:sfWithin(?trackPoint, ?stateWKT))
    }
  }
  {
    SELECT ?cyclone ?name (MIN(?trackDate) AS ?landfallDate)
    WHERE {
      gokg:LouisianaState geosparql:hasGeometry ?stateGeom .
      ?stateGeom geosparql:asWKT ?stateWKT .
      ?cyclone a goo:HurricaneEventRecord ;
               schema:name ?name ;
               goo:hasTrackRecord ?track .
      ?track a goo:HurricaneTrackRecord ;
             goo:recordDateTime ?trackDate ;
             goo:status "HU"^^xsd:string ;
             goo:lat ?trackLat ;
             goo:lon ?trackLon .
      BIND(STRDT(CONCAT("POINT(", STR(?trackLon), " ", STR(?trackLat), ")"), geosparql:wktLiteral) AS ?trackPoint)
      FILTER (MONTH(?trackDate) = 8)
      FILTER (geof:sfWithin(?trackPoint, ?stateWKT))
    }
    GROUP BY ?cyclone ?name
  }
}
ORDER BY ?landfallDate ?name

PREFIX goo:        <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:       <http://example.org/resource#>
PREFIX geosparql:  <http://www.opengis.net/ont/geosparql#>
PREFIX geof:       <http://www.opengis.net/def/function/geosparql/>
PREFIX xsd:        <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:       <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?state ?tornadoCount ?hurricaneCount ?thunderstormCount ?wildfireCount (CONCAT(STR(?tornadoCount), ":", STR(?hurricaneCount), ":", STR(?thunderstormCount), ":", STR(?wildfireCount)) AS ?eventRatio)
WHERE {
  VALUES ?state { gokg:FloridaState gokg:CaliforniaState }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?tornado) AS ?tornadoCountRaw)
    WHERE {
      VALUES ?state { gokg:FloridaState gokg:CaliforniaState }
      ?tornado a goo:TornadoEventRecord ;
               goo:occurredInState ?state .
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?hurricane) AS ?hurricaneCountRaw)
    WHERE {
      VALUES ?state { gokg:FloridaState gokg:CaliforniaState }
      ?state geosparql:hasGeometry ?stateGeom .
      ?stateGeom geosparql:asWKT ?stateWKT .
      ?hurricane a goo:HurricaneEventRecord ;
                 goo:hasTrackRecord ?track .
      ?track a goo:HurricaneTrackRecord ;
             goo:lat ?trackLat ;
             goo:lon ?trackLon .
      BIND(STRDT(CONCAT("POINT(", STR(?trackLon), " ", STR(?trackLat), ")"), geosparql:wktLiteral) AS ?trackPoint)
      FILTER (geof:sfWithin(?trackPoint, ?stateWKT))
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?thunderstorm) AS ?thunderstormCountRaw)
    WHERE {
      VALUES ?state { gokg:FloridaState gokg:CaliforniaState }
      ?thunderstorm a goo:StormEventRecord ;
                    goo:occurredInState ?state ;
                    goo:stormEventType ?thunderstormType .
      FILTER (CONTAINS(LCASE(STR(?thunderstormType)), "thunderstorm"))
    }
    GROUP BY ?state
  }
  OPTIONAL {
    SELECT ?state (COUNT(DISTINCT ?wildfire) AS ?wildfireCountRaw)
    WHERE {
      VALUES ?state { gokg:FloridaState gokg:CaliforniaState }
      ?wildfire a goo:StormEventRecord ;
                goo:occurredInState ?state ;
                goo:stormEventType ?wildfireType .
      FILTER (LCASE(STR(?wildfireType)) = "wildfire")
    }
    GROUP BY ?state
  }
  BIND(COALESCE(?tornadoCountRaw, 0) AS ?tornadoCount)
  BIND(COALESCE(?hurricaneCountRaw, 0) AS ?hurricaneCount)
  BIND(COALESCE(?thunderstormCountRaw, 0) AS ?thunderstormCount)
  BIND(COALESCE(?wildfireCountRaw, 0) AS ?wildfireCount)
}
ORDER BY ?state

PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?event ?county ?eventType ?eventStart ?record ?recordDate ?numOutages
WHERE {
  ?event a goo:StormEventRecord ;
         goo:occurredInState gokg:FloridaState ;
         goo:occurredInCounty ?county ;
         goo:stormEventType ?eventType ;
         goo:eventStartTime ?eventStart .
  ?record a goo:CustomerOutageRecord ;
          goo:representsCounty ?county ;
          goo:recordDateTime ?recordDate ;
          goo:numberOfOutages ?numOutages .
  FILTER (?numOutages > 50000)
  FILTER (?eventStart <= ?recordDate)
  FILTER (SUBSTR(STR(?eventStart), 1, 10) = SUBSTR(STR(?recordDate), 1, 10))
}
ORDER BY ?county ?eventStart DESC(?numOutages)
LIMIT 10

PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?event ?county ?eventType ?eventStart ?record ?recordDate ?numOutages
WHERE {
  ?event a goo:StormEventRecord ;
         goo:occurredInState gokg:FloridaState ;
         goo:occurredInCounty ?county ;
         goo:stormEventType ?eventType ;
         goo:eventStartTime ?eventStart .
  ?record a goo:CustomerOutageRecord ;
          goo:representsCounty ?county ;
          goo:recordDateTime ?recordDate ;
          goo:numberOfOutages ?numOutages .
  FILTER (?numOutages > 50000)
  FILTER (?eventStart <= ?recordDate)
  # Same-day constraint removed: event may start before a later outage record in the same county.
